import React from "react";
import { ArrowLeft } from "lucide-react";
import { useCurrency } from "../context/CurrencyContext";

export default function TransactionReceiptScreen({ transaction, onBack, darkMode }) {
  const { formatAmount } = useCurrency();

  if (!transaction) {
    return (
      <div className="p-6">
        <button onClick={onBack}>← Back</button>
        <p className="mt-6">Transaction not found.</p>
      </div>
    );
  }

  const isDeposit = transaction.type.includes("deposit");

  return (
    <div className={`min-h-screen px-6 pt-6 ${darkMode ? "bg-gray-900 text-gray-100" : "bg-gray-50 text-gray-900"}`}>
      <button onClick={onBack} className="mb-6 flex items-center gap-2">
        <ArrowLeft size={20} /> Back
      </button>

      <div className={`p-6 rounded-2xl ${darkMode ? "bg-gray-800" : "bg-white"} shadow`}>
        <h1 className="text-xl font-bold mb-4">Transaction Receipt</h1>

        <div className="space-y-3 text-sm">
          <p><strong>Type:</strong> {isDeposit ? "Deposit" : "Withdrawal"}</p>
          <p><strong>Amount:</strong> {formatAmount(transaction.amount)}</p>
          <p><strong>Date:</strong> {transaction.date}</p>
          <p><strong>Reference:</strong> {transaction.reference || "—"}</p>
        </div>
      </div>
    </div>
  );
}
